import{_ as o,o as i,c as e,a2 as s}from"./chunks/framework.CY0RMtsF.js";const r="/mug-typography-docs/image/muglab_preset_list.webp",a="/mug-typography-docs/image/resolve_edit_page.webp",n="/mug-typography-docs/image/resolve_fusion_page.webp",_=JSON.parse('{"title":"使い方・クイックスタート","description":"","frontmatter":{"title":"使い方・クイックスタート"},"headers":[],"relativePath":"guide/getting-started.md","filePath":"guide/getting-started.md"}'),g={name:"guide/getting-started.md"};function l(p,t,c,d,u,h){return i(),e("div",null,[...t[0]||(t[0]=[s('<h1 id="使い方" tabindex="-1">使い方 <a class="header-anchor" href="#使い方" aria-label="Permalink to &quot;使い方&quot;">​</a></h1><p>本プラグインは、入力したいテキストの長さや文字の複雑さに合わせて、処理の制限値（最大文字数・最大パーツ数）が異なる3つのプリセットに分かれています。用途に合わせて選択してご使用ください。</p><ul><li><strong>Mug Typography (Low)</strong>: 入力するテキストが短い場合（最大16文字 / 60パーツまで）に使用します。動作が最も軽快です。</li><li><strong>Mug Typography (Mid) [推奨]</strong>: 通常のテキスト入力向けです（最大30文字 / 84パーツまで）。<strong>どれを使用すればよいか迷った場合は、まずこの「Mid」を選択してください。</strong></li><li><strong>Mug Typography (High)</strong>: 長文テキストや、画数の多い複雑な漢字を多く含める場合（最大60文字 / 170パーツまで）に使用します。制限値が大きいぶんメモリ使用量も多く、<strong>搭載メモリの少ない環境ではクラッシュのリスクが高くなります。</strong></li><li><strong>Mug Typography Lite (Low / Mid / High)</strong>: 個別パーツごとの調整パラメータ（Part Settings）を排除してロードと処理を高速化している軽量版プリセットです。個別パーツの編集が不要な場合はこちらを推奨します。 <ul><li><strong>制限値の自動緩和</strong>: 最大文字数が通常版の <strong>1.5倍</strong> に自動的に緩和されます（LiteLow: 最大24文字, LiteMid: 最大45文字, LiteHigh: 最大90文字）。</li><li><strong>最大パーツ数の上限解放</strong>: 個別パラメータを保持しないため、描画できる上限である <strong>512パーツ</strong> まで制限なく許容されます。</li></ul></li></ul><p><img src="'+r+'" alt="MugLab エフェクトライブラリのプリセット一覧"></p><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p><strong>通常は Low もしくは Mid (またはそれらの Lite 版) を使用し、文字数・パーツ数が足りない場合にのみ High / LiteHigh を使用してください。</strong> High は制限値が大きいぶんメモリを多く消費するため、搭載メモリの少ない環境では DaVinci Resolve ごとクラッシュする恐れがあります。 もし High / LiteHigh でクラッシュする場合は、<code>preferences.json</code> で High の <code>maxCharacters</code> / <code>maxParts</code> を実際に必要な値まで下げることで、安定して使用できる場合があります（調整方法は付録の「<a href="#preferences-customization-ja">環境設定のカスタマイズ (preferences.json)</a>」を参照）。</p></div><h2 id="edit-ページ" tabindex="-1">Edit ページ <a class="header-anchor" href="#edit-ページ" aria-label="Permalink to &quot;Edit ページ&quot;">​</a></h2><p>エフェクトライブラリの <strong>Open FX</strong> には、用途に合わせて以下の2つの場所に上記の各プリセット（Low / Mid / High / Lite Low / Lite Mid / Lite High）が用意されています。タイムラインに配置または適用してご使用ください。</p><ul><li><strong>Open FX → Generators → MugLab</strong> (ジェネレーター版) <ul><li>タイムライン上に新規クリップとして直接配置したい場合に使用します。ドラッグ＆ドロップでタイムライン上に配置できます。</li></ul></li><li><strong>Open FX → Filters → MugLab</strong> (フィルター/エフェクト版) <ul><li>既存のクリップに対して、エフェクトとして本プラグインを適用したい場合に使用します。</li><li>なお、<strong>Color ページ</strong> などの他のページではこちら（Filters）のみが表示されますので、それを選択してご使用ください。</li><li>※ グラフィックボードのエラー等によりCPU描画に切り替わった場合は、仕様上背景との合成がスキップされ、テキストのみが表示される状態になります（詳細は付録の「<a href="#limitations-ja">制限事項</a>」を参照してください）。</li></ul></li></ul><p>配置または適用後、右側の <strong>Inspector</strong> パネルにパラメーターが表示されます。</p><h3 id="ビューア上での操作を有効にする" tabindex="-1">ビューア上での操作を有効にする <a class="header-anchor" href="#ビューア上での操作を有効にする" aria-label="Permalink to &quot;ビューア上での操作を有効にする&quot;">​</a></h3><p>プレビュー画面上でのハンドル操作（移動・回転・スケールなど）を使うには、タイムライン左下の四角く囲った部分を <strong>クリック → Open FX Overlay</strong> に設定してください。</p><p><img src="'+a+'" alt="Edit ページでの使用例"></p><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>Edit ページには DaVinci Resolve の仕様による制限があります。詳細は付録の「<a href="#limitations-ja">制限事項</a>」を参照してください。</p></div><h2 id="fusion-ページ" tabindex="-1">Fusion ページ <a class="header-anchor" href="#fusion-ページ" aria-label="Permalink to &quot;Fusion ページ&quot;">​</a></h2><p>Fusion ページでは、メニューの <strong>Tools → OpenFX → MugLab</strong> 配下の <strong>Mug Typography (Low)</strong>, <strong>Mug Typography (Mid)</strong>, <strong>Mug Typography (High)</strong> から必要なプリセットのノードをノードグラフに追加して使用します。ノードを選択すると右側の <strong>Inspector</strong> にパラメーターが表示されます。</p><p><img src="'+n+'" alt="Fusion ページでの使用例"></p><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>Fusion ページでは、入力（Input）端子に映像を接続すればフィルターとして動作し、接続しない場合はジェネレーターとして機能します。ただし、パフォーマンスの観点から接続しての使用は推奨しません（また、CPU描画に切り替わった場合は、背景との合成がスキップされ、テキストのみが表示されます）。</p></div><hr><p><a id="basic-concepts-ja"></a></p>',19)])])}const b=o(g,[["render",l]]);export{_ as __pageData,b as default};
